 * SMS message templates keyed by notification type.
 * Each template receives the payload and returns a plain text string.
 * Messages are kept short to fit within SMS length limits.
 */
const smsTemplates: Record<NotificationType, (payload: NotificationPayload) => string> = {
  order_confirmation(payload) {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    return `TaskFlow Pro: Order ${orderId} confirmed. ${payload.body}`;
  },

  order_status_update(payload) {
    const orderId = (payload.metadata?.orderId as string) ?? 'N/A';
    const newStatus = (payload.metadata?.newStatus as string) ?? '';
    return `TaskFlow Pro: Order ${orderId} is now ${newStatus}.`;
  },

  user_welcome(payload) {
    return `Welcome to TaskFlow Pro, ${payload.recipient}! Your account is ready.`;
  },

  user_updated(payload) {
    return `TaskFlow Pro: Your account has been updated.`;
  },
};

/**
 * Validate phone number in E.164 format: + followed by 7-15 digits.
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{6,14}$/.test(phone);
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];

  constructor(private config: SmsConfig = defaultSmsConfig) {}

  /**
   * Render the notification body into a plain text SMS message
   * using the appropriate template for the notification type.
   * Truncates to maxLength if necessary.
   */
  renderTemplate(payload: NotificationPayload): string {
    const templateFn = smsTemplates[payload.notificationType];
    const message = templateFn(payload);

    if (message.length > this.config.maxLength) {
      return message.substring(0, this.config.maxLength - 3) + '...';
    }
    return message;
  }

  /**
   * Resolve and validate the recipient phone number.
   * Returns the validated phone number or null if invalid.
   */
