    const phone = payload.recipient.trim();
    if (!phone || !isValidPhoneNumber(phone)) {
      this.logger.warn(`Invalid recipient phone number: "${payload.recipient}"`);
      return null;
    }
    return phone;
  }

  /**
   * Send an SMS notification.
   *
   * 1. Validates the recipient phone number.
   * 2. Renders the message body from templates.
   * 3. Records the SMS (in-memory for testing; swap for real provider in production).
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    try {
      const recipient = this.resolveRecipient(payload);
      if (!recipient) {
        return false;
      }

      const body = this.renderTemplate(payload);

      this.logger.info(`Sending SMS from "${this.config.fromNumber}" to ${recipient}: ${body.substring(0, 50)}...`);

      this.sentMessages.push({
        to: recipient,
        from: this.config.fromNumber,
        body,
        sentAt: new Date(),
      });

      return true;
    } catch (error) {
      this.logger.error(
        `Failed to send SMS to ${payload.recipient}: ${error instanceof Error ? error.message : String(error)}`,
